INSERT INTO `chat_history` (`id`, `email`, `user_message`, `bot_response`, `created_at`, `session_id`, `model_device`, `battery_health`, `storage_size`, `sinyal_status`, `biometrik_status`, `part_status`, `kamera_status`, `icloud_status`, `jangka_pakai`, `skor_persen`) VALUES
	(422, 'admin@gmail.com', 'ip 17 pro max', 'Terima kasih. Selanjutnya, silakan masukkan varian <b>warna resmi</b> dari unit iPhone tersebut.<br><span style=\'color:var(--text-muted); font-size:12px;\'>Rekomendasi opsi: DeepBlue, Titanium, SpaceGray, Orange</span>', '2026-07-16 17:28:22', 'session_6a5911ce16e976.38233055', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
	(423, 'admin@gmail.com', 'DeepBlue', 'Berapakah kapasitas penyimpanan internal (Storage) perangkat Anda?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Opsi standar: 64 GB, 128 GB, 256 GB, atau 512 GB</span>', '2026-07-16 17:28:30', 'session_6a5911ce16e976.38233055', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
	(424, 'admin@gmail.com', '64', 'Mohon sebutkan persentase kapasitas maksimal sisa dari sitem daya kesehatan baterai unit perangkat tersebut.<br><span style=\'color:var(--text-muted); font-size:12px;\'>Contoh input: 85 atau BH 90</span>', '2026-07-16 17:28:33', 'session_6a5911ce16e976.38233055', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
	(425, 'admin@gmail.com', '100', 'Bagaimanakah status distribusi jaminan/garansi unit yang diperiksa?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Pilihan: Resmi <b>iBox</b>, Eks Internasional (<b>Inter</b>), atau <b>WiFi Only</b></span>', '2026-07-16 17:28:37', 'session_6a5911ce16e976.38233055', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
	(426, 'admin@gmail.com', 'ibox', 'Bagaimanakah kondisi dan status penangkapan <b>Jaringan Sinyal Seluler</b> pada unit gadget tersebut?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Opsi: Aman All Operator atau Terblokir / Terkunci (WiFi Only)</span>', '2026-07-16 17:28:40', 'session_6a5911ce16e976.38233055', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
	(427, 'admin@gmail.com', 'aman', 'Apakah sistem keamanan sensor biometrik perangkat (seperti fungsi <b>Face ID</b> atau <b>Touch ID</b>) masih berfungsi normal?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Pilihan: Aktif Normal atau Nonaktif / Rusak</span>', '2026-07-16 17:28:42', 'session_6a5911ce16e976.38233055', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
	(428, 'admin@gmail.com', 'aktif', 'Apakah fitur **True Tone** pada layar LCD terdeteksi aktif dan seluruh komponen unit masih original?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Pilihan: Original / Aktif atau Komponen Pernah Diganti (Unknown Part)</span>', '2026-07-16 17:28:45', 'session_6a5911ce16e976.38233055', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
	(429, 'admin@gmail.com', 'ori', 'Bagaimanakah status performa fungsionalitas visual kamera utama dan kamera depan gadget saat ini?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Pilihan: Jernih & Normal atau Mengalami Kendala (Getar / Blur / Mati)</span>', '2026-07-16 17:28:47', 'session_6a5911ce16e976.38233055', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
	(430, 'admin@gmail.com', 'jernih', 'Apakah akun otentikasi keamanan <b>iCloud</b> unit berada dalam status bersih, bebas di-reset, dan kosong?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Pilihan: Bersih (Bebas Reset) atau Terkunci / Menggunakan Metode Bypass</span>', '2026-07-16 17:28:50', 'session_6a5911ce16e976.38233055', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
	(431, 'admin@gmail.com', 'bersih', 'Sebagai informasi penutup diagnosa, mohon sebutkan perkiraan masa durasi penggunaan aktif perangkat tersebut (dalam satuan tahun).<br><span style=\'color:var(--text-muted); font-size:12px;\'>Contoh input: 1 atau 2 tahun</span>', '2026-07-16 17:28:55', 'session_6a5911ce16e976.38233055', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
