	(433, 'dicki.firgiawan@nevorix.ai', 'ip 17 pro max', 'Terima kasih. Selanjutnya, silakan masukkan varian <b>warna resmi</b> dari unit iPhone tersebut.<br><span style=\'color:var(--text-muted); font-size:12px;\'>Rekomendasi opsi: DeepBlue, Titanium, SpaceGray, Orange</span>', '2026-07-16 17:32:52', 'session_6a5915bdc73db8.00426095', NULL, NULL, NULL, '0', '0', '0', '0', '0', '1', 100),
