	(490, 'dicki.firgiawan@nevorix.ai', 'normal', 'Apakah fitur **True Tone** pada layar LCD terdeteksi aktif dan seluruh komponen unit masih original?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Pilihan: Original / Aktif atau Komponen Pernah Diganti (Unknown Part)</span>', '2026-07-17 15:19:21', 'session_6a5a47c0d17147.38853513', NULL, NULL, NULL, '2', '0', '0', '0', '0', '1', 35),
	(491, 'dicki.firgiawan@nevorix.ai', 'unknow part', 'Apakah fitur **True Tone** pada layar LCD terdeteksi aktif dan seluruh komponen unit masih original?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Pilihan: Original / Aktif atau Komponen Pernah Diganti (Unknown Part)</span>', '2026-07-17 15:19:31', 'session_6a5a47c0d17147.38853513', NULL, NULL, NULL, '2', '0', '0', '0', '0', '1', 35),
	(492, 'dicki.firgiawan@nevorix.ai', 'aman', 'Bagaimanakah status performa fungsionalitas visual kamera utama dan kamera depan gadget saat ini?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Pilihan: Jernih & Normal atau Mengalami Kendala (Getar / Blur / Mati)</span>', '2026-07-17 15:19:33', 'session_6a5a47c0d17147.38853513', NULL, NULL, NULL, '2', '0', '0', '0', '0', '1', 35),
	(493, 'dicki.firgiawan@nevorix.ai', 'jernih', 'Apakah akun otentikasi keamanan <b>iCloud</b> unit berada dalam status bersih, bebas di-reset, dan kosong?<br><span style=\'color:var(--text-muted); font-size:12px;\'>Pilihan: Bersih (Bebas Reset) atau Terkunci / Menggunakan Metode Bypass</span>', '2026-07-17 15:19:35', 'session_6a5a47c0d17147.38853513', NULL, NULL, NULL, '2', '0', '0', '0', '0', '1', 35),
	(494, 'dicki.firgiawan@nevorix.ai', 'terkunci', 'Sebagai informasi penutup diagnosa, mohon sebutkan perkiraan masa durasi penggunaan aktif perangkat tersebut (dalam satuan tahun).<br><span style=\'color:var(--text-muted); font-size:12px;\'>Contoh input: 1 atau 2 tahun</span>', '2026-07-17 15:19:48', 'session_6a5a47c0d17147.38853513', NULL, NULL, NULL, '2', '0', '0', '0', '1', '1', 35),
